const updateSantaRule = `-- name: UpdateSantaRule :one
UPDATE santa_rules
SET
    rule_type = $1::santa_rule_type,
    identifier = $2,
    name = $3,
    description = $4,
    custom_message = $5,
    custom_url = $6,
    updated_at = now()
WHERE id = $7
RETURNING id, rule_type, identifier, name, description, custom_message, custom_url, created_at, updated_at
`

type UpdateSantaRuleParams struct {
	RuleType      SantaRuleType `json:"rule_type"`
	Identifier    string        `json:"identifier"`
	Name          string        `json:"name"`
	Description   string        `json:"description"`
	CustomMessage string        `json:"custom_message"`
	CustomURL     string        `json:"custom_url"`
	ID            int64         `json:"id"`
}

